$_MODULE['<{retractationcommande}prestashop>pdf-accuse_0acbcac4025fa540444c48cd5594df23'] = 'Spese di spedizione (rimborsate — recesso totale)';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_b01439257d2c4065fdfa7b0ece09c658'] = 'Importo da rimborsare (stima)';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_d7946d02e12c5949ea9345ba89b095c4'] = 'Recesso parziale: le spese di spedizione sono rimborsate in proporzione ai beni restituiti (art. L221-24 del Codice del consumo francese). L\'importo definitivo Le sarà confermato dal nostro servizio clienti.';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_a326ee07399805b54dda859c82d08e17'] = 'Messaggio del consumatore';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_b6aaa57d1a0559fa210245cf8167735e'] = 'Prosecuzione della procedura';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_fb258aad76f4abfa89becfda83844199'] = 'La Sua richiesta sarà verificata dal nostro servizio clienti (rispetto del termine legale, esclusioni previste dall\'articolo L221-28 del Codice del consumo francese). Se conforme, Le verrà trasmessa via e-mail la procedura di reso. La preghiamo di non rispedire il/i prodotto/i prima di averla ricevuta. Il rimborso avverrà entro 14 giorni dal recupero del bene o dalla ricezione della prova di spedizione, con lo stesso mezzo di pagamento utilizzato per l\'ordine (art. L221-24). Le spese dirette di restituzione restano a Suo carico (art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_cfdcc6b063cf374f1884714702a0756f'] = 'Poiché il Suo ordine non era ancora stato spedito al momento della Sua richiesta, non sarà necessaria alcuna restituzione di prodotto. Dopo la verifica da parte del nostro servizio clienti (esclusioni previste dall\'articolo L221-28 del Codice del consumo francese), la spedizione verrà annullata e l\'intero importo versato Le sarà rimborsato entro 14 giorni dalla Sua richiesta, con lo stesso mezzo di pagamento utilizzato per l\'ordine (art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_5c2d9de00ffacf2c364b00b78de3b779'] = 'Il presente documento vale come conferma di ricezione del Suo recesso. Lo conservi — il Suo riferimento da indicare in ogni comunicazione:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cd869423e6e1712e244df7d46926ae55'] = 'Promemoria dei Suoi diritti — diritto di recesso';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_28f6dc3c50525ce42dc3c3c6230b2e04'] = 'Il termine';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_24e62b7e04a04435c6493925063099d7'] = 'Dispone di un termine di 14 giorni per recedere, senza dover motivare la Sua decisione (art. L221-18 del Codice del consumo francese). Il conteggio inizia il giorno successivo alla consegna del bene (o alla conclusione del contratto per una prestazione di servizi). Se il termine scade di sabato, domenica o in un giorno festivo, è prorogato fino al primo giorno lavorativo successivo.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_ca4bdfe353ca54b512aa784846d90e0f'] = 'Il rimborso';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_6541cabbb055c914336220caeaf4b99e'] = 'Il rimborso riguarda la totalità delle somme versate, comprese le spese di spedizione standard (in proporzione in caso di recesso parziale). Avviene entro 14 giorni dal recupero del bene o dalla ricezione della prova della sua spedizione, con lo stesso mezzo di pagamento utilizzato per l\'ordine (art. L221-24). Le spese dirette di restituzione del bene restano a Suo carico (art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_364ec46bb0eefd5863d785498e0c8539'] = 'Le eccezioni (art. L221-28)';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cb0665e6df823aae3b2992c440175070'] = 'Il diritto di recesso non può essere esercitato in particolare per:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_7e1ea9778afc631312c1791d817f91c0'] = 'i beni confezionati secondo le Sue specifiche o chiaramente personalizzati;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0b6b365148cc6a798a4d9bec4e636d96'] = 'i beni che rischiano di deteriorarsi o scadere rapidamente;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_9efb6136f62e038628c899b282f64011'] = 'i beni sigillati aperti dopo la consegna che non possono essere restituiti per motivi di igiene o di protezione della salute;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_8b8f626ccf32831a3fee474f675ea152'] = 'le registrazioni audio/video o i software sigillati aperti dopo la consegna;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_01449e6b663bbee9d407376945b3c9b6'] = 'i contenuti digitali forniti senza supporto materiale la cui esecuzione è iniziata con il Suo consenso;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_1d3b84dba66d1eb114fd8af178aa04d6'] = 'i beni inscindibilmente mescolati con altri articoli dopo la consegna.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0095888b608335ea5982af9ada860f76'] = 'Il seguito della Sua richiesta';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_109c56e11ccf08ecc9e243bd1c4cb25f'] = 'Il nostro servizio clienti verifica la Sua richiesta e Le invia poi la procedura di reso via e-mail. La preghiamo di non rispedire il/i prodotto/i prima di averla ricevuta, e di restituire i beni completi, nel loro stato originale.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_de7d1a2208e88e0679183aa747db6042'] = 'Ordine non spedito: non sarà necessaria alcuna restituzione di prodotto. Il nostro servizio clienti verifica la Sua richiesta, annulla la spedizione e procede al rimborso.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_2f45a1c26bcfdf568c08ed1a390d3cbd'] = 'In caso di controversia';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_804c0cd637a7c9607f4e30b77e11a8ba'] = 'Se ritiene che la Sua richiesta non sia stata trattata conformemente alla normativa, può contattare il nostro servizio clienti e quindi rivolgersi gratuitamente a un mediatore del consumo (art. L612-1 del Codice del consumo francese).';
$_MODULE['<{retractationcommande}prestashop>order-detail_40333b8af27e3198afa43c960e43a3b8'] = 'Diritto di recesso';
$_MODULE['<{retractationcommande}prestashop>order-detail_c611966bbf00695038db11996b48d73a'] = 'Richiesta';
$_MODULE['<{retractationcommande}prestashop>order-detail_13a014cb9de9f7cad88d5dafb70ecb41'] = 'del';
$_MODULE['<{retractationcommande}prestashop>order-detail_6b9a33cdf67eb8f5e2ae805805a7f706'] = 'Dispone di un termine legale di 14 giorni per recedere';
$_MODULE['<{retractationcommande}prestashop>order-detail_2cec369315350f7bdd5ed0f7c762be97'] = 'Recedere';
$_MODULE['<{retractationcommande}prestashop>demande_a54afcca3ecc3d5b4891b1a75c73192d'] = 'Ordine non trovato o accesso non autorizzato.';
$_MODULE['<{retractationcommande}prestashop>demande_ae6c41ce3d6f31f73f9d143bcae0f6b2'] = 'Questo ordine non è più ammissibile al recesso (termine legale scaduto o prodotti già in fase di recesso).';
$_MODULE['<{retractationcommande}prestashop>demande_3a6a3681876ab1e4c55fdecb70fab698'] = 'Il messaggio contiene caratteri non consentiti.';
