$_MODULE['<{retractationcommande}prestashop>demande_36c075970e7709b21dc06b19cb75c19e'] = 'Selezioni almeno un prodotto da recedere.';
$_MODULE['<{retractationcommande}prestashop>demande_b0998d501f75050aa4045d17399c25d0'] = 'Impossibile registrare la richiesta. La preghiamo di contattare il servizio clienti.';
$_MODULE['<{retractationcommande}prestashop>demande_9914a2c75cdd71876e656e7621e47300'] = 'Il Suo recesso è stato registrato con il riferimento %s. Le è stata inviata una conferma di ricezione via e-mail. Il nostro servizio clienti verificherà la Sua richiesta e Le trasmetterà la procedura di reso.';
$_MODULE['<{retractationcommande}prestashop>demande_f49c93cbb2dab9d8c4b41d7e8a0f346d'] = 'Il Suo recesso è stato registrato con il riferimento %s. Le è stata inviata una conferma di ricezione via e-mail. Poiché il Suo ordine non è ancora stato spedito, non sarà necessaria alcuna restituzione di prodotto: dopo la verifica, la spedizione verrà annullata e Le sarà effettuato il rimborso.';
$_MODULE['<{retractationcommande}prestashop>demande_5a06e6b127a7d1baaf18d35bde389969'] = 'Il nostro servizio clienti verificherà l\'ammissibilità della Sua richiesta (termine legale di 14 giorni, esclusioni dell\'articolo L221-28). Se conforme, Le verrà trasmessa via e-mail la procedura di reso, quindi il rimborso avverrà entro 14 giorni dal recupero del bene o dalla ricezione della prova di spedizione. La preghiamo di non rispedire il prodotto prima di aver ricevuto la procedura di reso.';
$_MODULE['<{retractationcommande}prestashop>demande_ba6e3c755dec44b85c76f4e9e919450b'] = 'Poiché il Suo ordine non è ancora stato spedito, non sarà necessaria alcuna restituzione di prodotto. Dopo la verifica della Sua richiesta da parte del nostro servizio clienti, la spedizione verrà annullata e l\'intero importo versato Le sarà rimborsato entro 14 giorni dalla Sua richiesta, con lo stesso mezzo di pagamento (art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>demande_b91f8258aeb37ba358b04427913bd6b1'] = 'Da verificare: termine di 14 giorni, esclusioni legali (art. L221-28), prodotti già restituiti.';
